patch:
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..df9d636377ca 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1850,6 +1850,49 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }

+  // or (fcmp olt/ole/ult/ule X, C1), (fcmp olt/ole/ult/ule X, C2)
+  //   -> fcmp olt/ole/ult/ule X, max(C1, C2)
+  // and (fcmp olt/ole/ult/ule X, C1), (fcmp olt/ole/ult/ule X, C2)
+  //   -> fcmp olt/ole/ult/ule X, min(C1, C2)
+  // or (fcmp ogt/oge/ugt/uge X, C1), (fcmp ogt/oge/ugt/uge X, C2)
+  //   -> fcmp ogt/oge/ugt/uge X, min(C1, C2)
+  // and (fcmp ogt/oge/ugt/uge X, C1), (fcmp ogt/oge/ugt/uge X, C2)
+  //   -> fcmp ogt/oge/ugt/uge X, max(C1, C2)
+  if (PredL == PredR && LHS0 == RHS0) {
+    const APFloat *C1, *C2;
+    if (match(LHS1, m_APFloatAllowPoison(C1)) &&
+        match(RHS1, m_APFloatAllowPoison(C2))) {
+      auto CmpRes = C1->compare(*C2);
+      if (CmpRes != APFloat::cmpUnordered) {
+        bool C1LessThanC2 = CmpRes == APFloat::cmpLessThan;
+        switch (PredL) {
+        case FCmpInst::FCMP_OLT:
+        case FCmpInst::FCMP_ULT:
+        case FCmpInst::FCMP_OLE:
+        case FCmpInst::FCMP_ULE:
+          // For 'less than' predicates, the larger constant gives the less
+          // restrictive comparison.
+          return IsAnd ? (C1LessThanC2 ? static_cast<Value *>(LHS)
+                                       : static_cast<Value *>(RHS))
+                       : (C1LessThanC2 ? static_cast<Value *>(RHS)
+                                       : static_cast<Value *>(LHS));
+        case FCmpInst::FCMP_OGT:
+        case FCmpInst::FCMP_UGT:
+        case FCmpInst::FCMP_OGE:
+        case FCmpInst::FCMP_UGE:
+          // For 'greater than' predicates, the smaller constant gives the less
+          // restrictive comparison.
+          return IsAnd ? (C1LessThanC2 ? static_cast<Value *>(RHS)
+                                       : static_cast<Value *>(LHS))
+                       : (C1LessThanC2 ? static_cast<Value *>(LHS)
+                                       : static_cast<Value *>(RHS));
+        default:
+          break;
+        }
+      }
+    }
+  }
+
   return nullptr;
 }

